        vnc_framebuffer_update(vs, absolute, 0,

                               surface_width(vs->vd->ds),

                               surface_height(vs->vd->ds),

                               VNC_ENCODING_POINTER_TYPE_CHANGE);

        vnc_unlock_output(vs);

        vnc_flush(vs);

    }

    vs->absolute = absolute;

}

