    struct target_rt_sigframe *frame;

    abi_ulong frame_addr = env->xregs[31];



    if (frame_addr & 15) {

        goto badframe;

    }



    if  (!lock_user_struct(VERIFY_READ, frame, frame_addr, 1)) {

