                                       cds + FF_INPUT_BUFFER_PADDING_SIZE);

    cdp = st->codec->extradata + st->codec->extradata_size;

    *cdp++ = os->psize >> 8;

    *cdp++ = os->psize & 0xff;

    memcpy (cdp, os->buf + os->pstart, os->psize);

    st->codec->extradata_size = cds;



    return 1;

