                            s->block_last_index[i] = -1;

                        }

                        cbp+=cbp;

                    }

                }

            }

        }else{

            for(i=0;i<6;i++)

                s->block_last_index[i] = -1;

        }

    }



    s->current_picture.mb_type[ s->mb_x + s->mb_y*s->mb_stride ]= mb_type;



