    s->compression_type = bytestream2_get_byte(&s->gb);

    s->filter_type      = bytestream2_get_byte(&s->gb);

    s->interlace_type   = bytestream2_get_byte(&s->gb);

    bytestream2_skip(&s->gb, 4); /* crc */

