void HELPER(simcall)(CPUXtensaState *env)

{

    uint32_t *regs = env->regs;



    switch (regs[2]) {

    case TARGET_SYS_exit:

        qemu_log("exit(%d) simcall\n", regs[3]);

        exit(regs[3]);

        break;



    case TARGET_SYS_read:

    case TARGET_SYS_write:

        {

            bool is_write = regs[2] == TARGET_SYS_write;

            uint32_t fd = regs[3];

            uint32_t vaddr = regs[4];

            uint32_t len = regs[5];



            while (len > 0) {

                target_phys_addr_t paddr =

                    cpu_get_phys_page_debug(env, vaddr);

                uint32_t page_left =

                    TARGET_PAGE_SIZE - (vaddr & (TARGET_PAGE_SIZE - 1));

                uint32_t io_sz = page_left < len ? page_left : len;

                target_phys_addr_t sz = io_sz;

                void *buf = cpu_physical_memory_map(paddr, &sz, is_write);



                if (buf) {

                    vaddr += io_sz;

                    len -= io_sz;

                    regs[2] = is_write ?

                        write(fd, buf, io_sz) :

                        read(fd, buf, io_sz);

                    regs[3] = errno;

                    cpu_physical_memory_unmap(buf, sz, is_write, sz);

                    if (regs[2] == -1) {

                        break;

                    }

                } else {


                    regs[3] = EINVAL;

                    break;

                }

            }

        }

        break;



    case TARGET_SYS_open:

        {

            char name[1024];

            int rc;

            int i;



            for (i = 0; i < ARRAY_SIZE(name); ++i) {

                rc = cpu_memory_rw_debug(

                        env, regs[3] + i, (uint8_t *)name + i, 1, 0);

                if (rc != 0 || name[i] == 0) {

                    break;

                }

            }



            if (rc == 0 && i < ARRAY_SIZE(name)) {

                regs[2] = open(name, regs[4], regs[5]);

                regs[3] = errno;

            } else {


                regs[3] = EINVAL;

            }

        }

        break;



    case TARGET_SYS_close:

        if (regs[3] < 3) {

            regs[2] = regs[3] = 0;

        } else {

            regs[2] = close(regs[3]);

            regs[3] = errno;

        }

        break;



    case TARGET_SYS_lseek:

        regs[2] = lseek(regs[3], (off_t)(int32_t)regs[4], regs[5]);

        regs[3] = errno;

        break;



    case TARGET_SYS_select_one:

        {

            uint32_t fd = regs[3];

            uint32_t rq = regs[4];

            uint32_t target_tv = regs[5];

            uint32_t target_tvv[2];



            struct timeval tv = {0};

            fd_set fdset;



            FD_ZERO(&fdset);

            FD_SET(fd, &fdset);



            if (target_tv) {

                cpu_memory_rw_debug(env, target_tv,

                        (uint8_t *)target_tvv, sizeof(target_tvv), 0);

                tv.tv_sec = (int32_t)tswap32(target_tvv[0]);

                tv.tv_usec = (int32_t)tswap32(target_tvv[1]);

            }

            regs[2] = select(fd + 1,

                    rq == SELECT_ONE_READ   ? &fdset : NULL,

                    rq == SELECT_ONE_WRITE  ? &fdset : NULL,

                    rq == SELECT_ONE_EXCEPT ? &fdset : NULL,

                    target_tv ? &tv : NULL);

            regs[3] = errno;

        }

        break;



    case TARGET_SYS_argc:

        regs[2] = 1;

        regs[3] = 0;

        break;



    case TARGET_SYS_argv_sz:

        regs[2] = 128;

        regs[3] = 0;

        break;



    case TARGET_SYS_argv:

        {

            struct Argv {

                uint32_t argptr[2];

                char text[120];

            } argv = {

                {0, 0},

                "test"

            };



            argv.argptr[0] = tswap32(regs[3] + offsetof(struct Argv, text));

            cpu_memory_rw_debug(

                    env, regs[3], (uint8_t *)&argv, sizeof(argv), 1);

        }

        break;



    case TARGET_SYS_memset:

        {

            uint32_t base = regs[3];

            uint32_t sz = regs[5];



            while (sz) {

                target_phys_addr_t len = sz;

                void *buf = cpu_physical_memory_map(base, &len, 1);



                if (buf && len) {

                    memset(buf, regs[4], len);

                    cpu_physical_memory_unmap(buf, len, 1, len);

                } else {

                    len = 1;

                }

                base += len;

                sz -= len;

            }

            regs[2] = regs[3];

            regs[3] = 0;

        }

        break;



    default:

        qemu_log("%s(%d): not implemented\n", __func__, regs[2]);



        break;

    }

}

static void decode_lpc(int32_t *coeffs, int mode, int length)

{

    int i;



    if (length < 2)

        return;



    if (mode == 1) {

        unsigned a1 = *coeffs++;

        for (i = 0; i < length - 1 >> 1; i++) {

            *coeffs   += a1;

            coeffs[1] += *coeffs;

            a1         = coeffs[1];

            coeffs    += 2;

        }

        if (length - 1 & 1)

            *coeffs += a1;

    } else if (mode == 2) {

        unsigned a1    = coeffs[1];

        unsigned a2    = a1 + *coeffs;

        coeffs[1] = a2;

        if (length > 2) {

            coeffs += 2;

            for (i = 0; i < length - 2 >> 1; i++) {

                unsigned a3    = *coeffs + a1;

                unsigned a4    = a3 + a2;

                *coeffs   = a4;

                a1        = coeffs[1] + a3;

                a2        = a1 + a4;

                coeffs[1] = a2;

                coeffs   += 2;

            }

            if (length & 1)

                *coeffs += a1 + a2;

        }

    } else if (mode == 3) {

        unsigned a1    = coeffs[1];

        unsigned a2    = a1 + *coeffs;

        coeffs[1] = a2;

        if (length > 2) {

            unsigned a3  = coeffs[2];

            unsigned a4  = a3 + a1;

            unsigned a5  = a4 + a2;

            coeffs[2] = a5;

            coeffs += 3;

            for (i = 0; i < length - 3; i++) {

                a3     += *coeffs;

                a4     += a3;

                a5     += a4;

                *coeffs = a5;

                coeffs++;

            }

        }

    }

}

