static void replication_start(ReplicationState *rs, ReplicationMode mode,

                              Error **errp)

{

    BlockDriverState *bs = rs->opaque;

    BDRVReplicationState *s;

    BlockDriverState *top_bs;

    int64_t active_length, hidden_length, disk_length;

    AioContext *aio_context;

    Error *local_err = NULL;



    aio_context = bdrv_get_aio_context(bs);

    aio_context_acquire(aio_context);

    s = bs->opaque;



    if (s->replication_state != BLOCK_REPLICATION_NONE) {

        error_setg(errp, "Block replication is running or done");

        aio_context_release(aio_context);

        return;

    }



    if (s->mode != mode) {

        error_setg(errp, "The parameter mode's value is invalid, needs %d,"

                   " but got %d", s->mode, mode);

        aio_context_release(aio_context);

        return;

    }



    switch (s->mode) {

    case REPLICATION_MODE_PRIMARY:

        break;

    case REPLICATION_MODE_SECONDARY:

        s->active_disk = bs->file;

        if (!s->active_disk || !s->active_disk->bs ||

                                    !s->active_disk->bs->backing) {

            error_setg(errp, "Active disk doesn't have backing file");

            aio_context_release(aio_context);

            return;

        }



        s->hidden_disk = s->active_disk->bs->backing;

        if (!s->hidden_disk->bs || !s->hidden_disk->bs->backing) {

            error_setg(errp, "Hidden disk doesn't have backing file");

            aio_context_release(aio_context);

            return;

        }



        s->secondary_disk = s->hidden_disk->bs->backing;

        if (!s->secondary_disk->bs || !bdrv_has_blk(s->secondary_disk->bs)) {

            error_setg(errp, "The secondary disk doesn't have block backend");

            aio_context_release(aio_context);

            return;

        }



        /* verify the length */

        active_length = bdrv_getlength(s->active_disk->bs);

        hidden_length = bdrv_getlength(s->hidden_disk->bs);

        disk_length = bdrv_getlength(s->secondary_disk->bs);

        if (active_length < 0 || hidden_length < 0 || disk_length < 0 ||

            active_length != hidden_length || hidden_length != disk_length) {

            error_setg(errp, "Active disk, hidden disk, secondary disk's length"

                       " are not the same");

            aio_context_release(aio_context);

            return;

        }



        if (!s->active_disk->bs->drv->bdrv_make_empty ||

            !s->hidden_disk->bs->drv->bdrv_make_empty) {

            error_setg(errp,

                       "Active disk or hidden disk doesn't support make_empty");

            aio_context_release(aio_context);

            return;

        }



        /* reopen the backing file in r/w mode */

        reopen_backing_file(bs, true, &local_err);

        if (local_err) {

            error_propagate(errp, local_err);

            aio_context_release(aio_context);

            return;

        }



        /* start backup job now */

        error_setg(&s->blocker,

                   "Block device is in use by internal backup job");



        top_bs = bdrv_lookup_bs(s->top_id, s->top_id, NULL);

        if (!top_bs || !bdrv_is_root_node(top_bs) ||

            !check_top_bs(top_bs, bs)) {

            error_setg(errp, "No top_bs or it is invalid");

            reopen_backing_file(bs, false, NULL);

            aio_context_release(aio_context);

            return;

        }

        bdrv_op_block_all(top_bs, s->blocker);

        bdrv_op_unblock(top_bs, BLOCK_OP_TYPE_DATAPLANE, s->blocker);



        backup_start(NULL, s->secondary_disk->bs, s->hidden_disk->bs, 0,

                     MIRROR_SYNC_MODE_NONE, NULL, false,

                     BLOCKDEV_ON_ERROR_REPORT, BLOCKDEV_ON_ERROR_REPORT,

                     BLOCK_JOB_INTERNAL, backup_job_completed, bs,

                     NULL, &local_err);

        if (local_err) {

            error_propagate(errp, local_err);

            backup_job_cleanup(bs);

            aio_context_release(aio_context);

            return;

        }

        break;

    default:

        aio_context_release(aio_context);

        abort();

    }



    s->replication_state = BLOCK_REPLICATION_RUNNING;



    if (s->mode == REPLICATION_MODE_SECONDARY) {

        secondary_do_checkpoint(s, errp);

    }



    s->error = 0;

    aio_context_release(aio_context);

}

static inline void RENAME(uyvyToUV)(uint8_t *dstU, uint8_t *dstV, const uint8_t *src1, const uint8_t *src2, int width, uint32_t *unused)

{

#if COMPILE_TEMPLATE_MMX

    __asm__ volatile(

        "movq "MANGLE(bm01010101)", %%mm4           \n\t"

        "mov                    %0, %%"REG_a"       \n\t"

        "1:                                         \n\t"

        "movq    (%1, %%"REG_a",4), %%mm0           \n\t"

        "movq   8(%1, %%"REG_a",4), %%mm1           \n\t"

        "pand                %%mm4, %%mm0           \n\t"

        "pand                %%mm4, %%mm1           \n\t"

        "packuswb            %%mm1, %%mm0           \n\t"

        "movq                %%mm0, %%mm1           \n\t"

        "psrlw                  $8, %%mm0           \n\t"

        "pand                %%mm4, %%mm1           \n\t"

        "packuswb            %%mm0, %%mm0           \n\t"

        "packuswb            %%mm1, %%mm1           \n\t"

        "movd                %%mm0, (%3, %%"REG_a") \n\t"

        "movd                %%mm1, (%2, %%"REG_a") \n\t"

        "add                    $4, %%"REG_a"       \n\t"

        " js                    1b                  \n\t"

        : : "g" ((x86_reg)-width), "r" (src1+width*4), "r" (dstU+width), "r" (dstV+width)

        : "%"REG_a

    );

#else

    int i;

    for (i=0; i<width; i++) {

        dstU[i]= src1[4*i + 0];

        dstV[i]= src1[4*i + 2];

    }

#endif

    assert(src1 == src2);

}

uint32_t vga_mem_readb(VGACommonState *s, hwaddr addr)

{

    int memory_map_mode, plane;

    uint32_t ret;



    /* convert to VGA memory offset */

    memory_map_mode = (s->gr[VGA_GFX_MISC] >> 2) & 3;

    addr &= 0x1ffff;

    switch(memory_map_mode) {

    case 0:

        break;

    case 1:

        if (addr >= 0x10000)

            return 0xff;

        addr += s->bank_offset;

        break;

    case 2:

        addr -= 0x10000;

        if (addr >= 0x8000)

            return 0xff;

        break;

    default:

    case 3:

        addr -= 0x18000;

        if (addr >= 0x8000)

            return 0xff;

        break;

    }



    if (s->sr[VGA_SEQ_MEMORY_MODE] & VGA_SR04_CHN_4M) {

        /* chain 4 mode : simplest access */

        ret = s->vram_ptr[addr];

    } else if (s->gr[VGA_GFX_MODE] & 0x10) {

        /* odd/even mode (aka text mode mapping) */

        plane = (s->gr[VGA_GFX_PLANE_READ] & 2) | (addr & 1);

        ret = s->vram_ptr[((addr & ~1) << 1) | plane];

    } else {

        /* standard VGA latched access */

        s->latch = ((uint32_t *)s->vram_ptr)[addr];



        if (!(s->gr[VGA_GFX_MODE] & 0x08)) {

            /* read mode 0 */

            plane = s->gr[VGA_GFX_PLANE_READ];

            ret = GET_PLANE(s->latch, plane);

        } else {

            /* read mode 1 */

            ret = (s->latch ^ mask16[s->gr[VGA_GFX_COMPARE_VALUE]]) &

                mask16[s->gr[VGA_GFX_COMPARE_MASK]];

            ret |= ret >> 16;

            ret |= ret >> 8;

            ret = (~ret) & 0xff;

        }

    }

    return ret;

}

