        if (!s->vm86) {

            if (s->cpl <= s->iopl) {

                gen_op_cli();

            } else {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            }

        } else {

            if (s->iopl == 3) {

                gen_op_cli();

            } else {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            }

        }

        break;

    case 0xfb: /* sti */

        if (!s->vm86) {

            if (s->cpl <= s->iopl) {

            gen_sti:

                gen_op_sti();

                /* interruptions are enabled only the first insn after sti */

                /* If several instructions disable interrupts, only the

                   _first_ does it */

                if (!(s->tb->flags & HF_INHIBIT_IRQ_MASK))

                    gen_op_set_inhibit_irq();

                /* give a chance to handle pending irqs */

                gen_op_jmp_im(s->pc - s->cs_base);

                gen_eob(s);

            } else {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            }

        } else {

            if (s->iopl == 3) {

                goto gen_sti;

            } else {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            }

        }

        break;

    case 0x62: /* bound */

        ot = dflag ? OT_LONG : OT_WORD;

        modrm = ldub_code(s->pc++);

        reg = (modrm >> 3) & 7;

        mod = (modrm >> 6) & 3;

        if (mod == 3)

            goto illegal_op;

        gen_op_mov_reg_T0[ot][reg]();

        gen_lea_modrm(s, modrm, &reg_addr, &offset_addr);

        if (ot == OT_WORD)

            gen_op_boundw(pc_start - s->cs_base);

        else

            gen_op_boundl(pc_start - s->cs_base);

        break;

    case 0x1c8 ... 0x1cf: /* bswap reg */

        reg = b & 7;

        gen_op_mov_TN_reg[OT_LONG][0][reg]();

        gen_op_bswapl_T0();

        gen_op_mov_reg_T0[OT_LONG][reg]();

        break;

    case 0xd6: /* salc */

        if (s->cc_op != CC_OP_DYNAMIC)

            gen_op_set_cc_op(s->cc_op);

        gen_op_salc();

        break;

    case 0xe0: /* loopnz */

    case 0xe1: /* loopz */

        if (s->cc_op != CC_OP_DYNAMIC)

            gen_op_set_cc_op(s->cc_op);

        /* FALL THRU */

    case 0xe2: /* loop */

    case 0xe3: /* jecxz */

        val = (int8_t)insn_get(s, OT_BYTE);

        next_eip = s->pc - s->cs_base;

        val += next_eip;

        if (s->dflag == 0)

            val &= 0xffff;

        gen_op_loop[s->aflag][b & 3](val, next_eip);

        gen_eob(s);

        break;

    case 0x130: /* wrmsr */

    case 0x132: /* rdmsr */

        if (s->cpl != 0) {

            gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

        } else {

            if (b & 2)

                gen_op_rdmsr();

            else

                gen_op_wrmsr();

        }

        break;

    case 0x131: /* rdtsc */

        gen_op_rdtsc();

        break;

    case 0x1a2: /* cpuid */

        gen_op_cpuid();

        break;

    case 0xf4: /* hlt */

        if (s->cpl != 0) {

            gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

        } else {

            if (s->cc_op != CC_OP_DYNAMIC)

                gen_op_set_cc_op(s->cc_op);

            gen_op_jmp_im(s->pc - s->cs_base);

            gen_op_hlt();

            s->is_jmp = 3;

        }

        break;

    case 0x100:

        modrm = ldub_code(s->pc++);

        mod = (modrm >> 6) & 3;

        op = (modrm >> 3) & 7;

        switch(op) {

        case 0: /* sldt */

            if (!s->pe || s->vm86)

                goto illegal_op;

            gen_op_movl_T0_env(offsetof(CPUX86State,ldt.selector));

            ot = OT_WORD;

            if (mod == 3)

                ot += s->dflag;

            gen_ldst_modrm(s, modrm, ot, OR_TMP0, 1);

            break;

        case 2: /* lldt */

            if (!s->pe || s->vm86)

                goto illegal_op;

            if (s->cpl != 0) {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            } else {

                gen_ldst_modrm(s, modrm, OT_WORD, OR_TMP0, 0);

                gen_op_jmp_im(pc_start - s->cs_base);

                gen_op_lldt_T0();

            }

            break;

        case 1: /* str */

            if (!s->pe || s->vm86)

                goto illegal_op;

            gen_op_movl_T0_env(offsetof(CPUX86State,tr.selector));

            ot = OT_WORD;

            if (mod == 3)

                ot += s->dflag;

            gen_ldst_modrm(s, modrm, ot, OR_TMP0, 1);

            break;

        case 3: /* ltr */

            if (!s->pe || s->vm86)

                goto illegal_op;

            if (s->cpl != 0) {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            } else {

                gen_ldst_modrm(s, modrm, OT_WORD, OR_TMP0, 0);

                gen_op_jmp_im(pc_start - s->cs_base);

                gen_op_ltr_T0();

            }

            break;

        case 4: /* verr */

        case 5: /* verw */

            if (!s->pe || s->vm86)

                goto illegal_op;

            gen_ldst_modrm(s, modrm, OT_WORD, OR_TMP0, 0);

            if (s->cc_op != CC_OP_DYNAMIC)

                gen_op_set_cc_op(s->cc_op);

            if (op == 4)

                gen_op_verr();

            else

                gen_op_verw();

            s->cc_op = CC_OP_EFLAGS;

            break;

        default:

            goto illegal_op;

        }

        break;

    case 0x101:

        modrm = ldub_code(s->pc++);

        mod = (modrm >> 6) & 3;

        op = (modrm >> 3) & 7;

        switch(op) {

        case 0: /* sgdt */

        case 1: /* sidt */

            if (mod == 3)

                goto illegal_op;

            gen_lea_modrm(s, modrm, &reg_addr, &offset_addr);

            if (op == 0)

                gen_op_movl_T0_env(offsetof(CPUX86State,gdt.limit));

            else

                gen_op_movl_T0_env(offsetof(CPUX86State,idt.limit));

            gen_op_st_T0_A0[OT_WORD + s->mem_index]();

            gen_op_addl_A0_im(2);

            if (op == 0)

                gen_op_movl_T0_env(offsetof(CPUX86State,gdt.base));

            else

                gen_op_movl_T0_env(offsetof(CPUX86State,idt.base));

            if (!s->dflag)

                gen_op_andl_T0_im(0xffffff);

            gen_op_st_T0_A0[OT_LONG + s->mem_index]();

            break;

        case 2: /* lgdt */

        case 3: /* lidt */

            if (mod == 3)

                goto illegal_op;

            if (s->cpl != 0) {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            } else {

                gen_lea_modrm(s, modrm, &reg_addr, &offset_addr);

                gen_op_ld_T1_A0[OT_WORD + s->mem_index]();

                gen_op_addl_A0_im(2);

                gen_op_ld_T0_A0[OT_LONG + s->mem_index]();

                if (!s->dflag)

                    gen_op_andl_T0_im(0xffffff);

                if (op == 2) {

                    gen_op_movl_env_T0(offsetof(CPUX86State,gdt.base));

                    gen_op_movl_env_T1(offsetof(CPUX86State,gdt.limit));

                } else {

                    gen_op_movl_env_T0(offsetof(CPUX86State,idt.base));

                    gen_op_movl_env_T1(offsetof(CPUX86State,idt.limit));

                }

            }

            break;

        case 4: /* smsw */

            gen_op_movl_T0_env(offsetof(CPUX86State,cr[0]));

            gen_ldst_modrm(s, modrm, OT_WORD, OR_TMP0, 1);

            break;

        case 6: /* lmsw */

            if (s->cpl != 0) {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            } else {

                gen_ldst_modrm(s, modrm, OT_WORD, OR_TMP0, 0);

                gen_op_lmsw_T0();

                gen_op_jmp_im(s->pc - s->cs_base);

                gen_eob(s);

            }

            break;

        case 7: /* invlpg */

            if (s->cpl != 0) {

                gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

            } else {

                if (mod == 3)

                    goto illegal_op;

                gen_lea_modrm(s, modrm, &reg_addr, &offset_addr);

                gen_op_invlpg_A0();

                gen_op_jmp_im(s->pc - s->cs_base);

                gen_eob(s);

            }

            break;

        default:

            goto illegal_op;

        }

        break;

    case 0x108: /* invd */

    case 0x109: /* wbinvd */

        if (s->cpl != 0) {

            gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

        } else {

            /* nothing to do */

        }

        break;

    case 0x63: /* arpl */

        if (!s->pe || s->vm86)

            goto illegal_op;

        ot = dflag ? OT_LONG : OT_WORD;

        modrm = ldub_code(s->pc++);

        reg = (modrm >> 3) & 7;

        mod = (modrm >> 6) & 3;

        rm = modrm & 7;

        if (mod != 3) {

            gen_lea_modrm(s, modrm, &reg_addr, &offset_addr);

            gen_op_ld_T0_A0[ot + s->mem_index]();

        } else {

            gen_op_mov_TN_reg[ot][0][rm]();

        }

        if (s->cc_op != CC_OP_DYNAMIC)

            gen_op_set_cc_op(s->cc_op);

        gen_op_arpl();

        s->cc_op = CC_OP_EFLAGS;

        if (mod != 3) {

            gen_op_st_T0_A0[ot + s->mem_index]();

        } else {

            gen_op_mov_reg_T0[ot][rm]();

        }

        gen_op_arpl_update();

        break;

    case 0x102: /* lar */

    case 0x103: /* lsl */

        if (!s->pe || s->vm86)

            goto illegal_op;

        ot = dflag ? OT_LONG : OT_WORD;

        modrm = ldub_code(s->pc++);

        reg = (modrm >> 3) & 7;

        gen_ldst_modrm(s, modrm, ot, OR_TMP0, 0);

        gen_op_mov_TN_reg[ot][1][reg]();

        if (s->cc_op != CC_OP_DYNAMIC)

            gen_op_set_cc_op(s->cc_op);

        if (b == 0x102)

            gen_op_lar();

        else

            gen_op_lsl();

        s->cc_op = CC_OP_EFLAGS;

        gen_op_mov_reg_T1[ot][reg]();

        break;

    case 0x118:

        modrm = ldub_code(s->pc++);

        mod = (modrm >> 6) & 3;

        op = (modrm >> 3) & 7;

        switch(op) {

        case 0: /* prefetchnta */

        case 1: /* prefetchnt0 */

        case 2: /* prefetchnt0 */

        case 3: /* prefetchnt0 */

            if (mod == 3)

                goto illegal_op;

            gen_lea_modrm(s, modrm, &reg_addr, &offset_addr);

            /* nothing more to do */

            break;

        default:

            goto illegal_op;

        }

        break;

    case 0x120: /* mov reg, crN */

    case 0x122: /* mov crN, reg */

        if (s->cpl != 0) {

            gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

        } else {

            modrm = ldub_code(s->pc++);

            if ((modrm & 0xc0) != 0xc0)

                goto illegal_op;

            rm = modrm & 7;

            reg = (modrm >> 3) & 7;

            switch(reg) {

            case 0:

            case 2:

            case 3:

            case 4:

                if (b & 2) {

                    gen_op_mov_TN_reg[OT_LONG][0][rm]();

                    gen_op_movl_crN_T0(reg);

                    gen_op_jmp_im(s->pc - s->cs_base);

                    gen_eob(s);

                } else {

                    gen_op_movl_T0_env(offsetof(CPUX86State,cr[reg]));

                    gen_op_mov_reg_T0[OT_LONG][rm]();

                }

                break;

            default:

                goto illegal_op;

            }

        }

        break;

    case 0x121: /* mov reg, drN */

    case 0x123: /* mov drN, reg */

        if (s->cpl != 0) {

            gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

        } else {

            modrm = ldub_code(s->pc++);

            if ((modrm & 0xc0) != 0xc0)

                goto illegal_op;

            rm = modrm & 7;

            reg = (modrm >> 3) & 7;

            /* XXX: do it dynamically with CR4.DE bit */

            if (reg == 4 || reg == 5)

                goto illegal_op;

            if (b & 2) {

                gen_op_mov_TN_reg[OT_LONG][0][rm]();

                gen_op_movl_drN_T0(reg);

                gen_op_jmp_im(s->pc - s->cs_base);

                gen_eob(s);

            } else {

                gen_op_movl_T0_env(offsetof(CPUX86State,dr[reg]));

                gen_op_mov_reg_T0[OT_LONG][rm]();

            }

        }

        break;

    case 0x106: /* clts */

        if (s->cpl != 0) {

            gen_exception(s, EXCP0D_GPF, pc_start - s->cs_base);

        } else {

            gen_op_clts();

            /* abort block because static cpu state changed */

            gen_op_jmp_im(s->pc - s->cs_base);

            gen_eob(s);

        }

        break;

    default:

        goto illegal_op;

    }

    /* lock generation */

    if (s->prefix & PREFIX_LOCK)

        gen_op_unlock();

    return s->pc;

 illegal_op:

    if (s->prefix & PREFIX_LOCK)

        gen_op_unlock();

    /* XXX: ensure that no lock was generated */

    gen_exception(s, EXCP06_ILLOP, pc_start - s->cs_base);

    return s->pc;

}

