    case 0xe9: /* jmp */

        ot = dflag ? OT_LONG : OT_WORD;

        val = insn_get(s, ot);

        val += s->pc - s->cs_base;

        if (s->dflag == 0)

            val = val & 0xffff;

        gen_jmp(s, val);

        break;

    case 0xea: /* ljmp im */

        {

            unsigned int selector, offset;



            ot = dflag ? OT_LONG : OT_WORD;

            offset = insn_get(s, ot);

            selector = insn_get(s, OT_WORD);



            gen_op_movl_T0_im(selector);

            gen_op_movl_T1_im(offset);

        }

        goto do_ljmp;

    case 0xeb: /* jmp Jb */

        val = (int8_t)insn_get(s, OT_BYTE);

        val += s->pc - s->cs_base;

        if (s->dflag == 0)

            val = val & 0xffff;

        gen_jmp(s, val);

        break;

