static int wma_decode_superframe(AVCodecContext *avctx, void *data,

                                 int *got_frame_ptr, AVPacket *avpkt)

{

    const uint8_t *buf = avpkt->data;

    int buf_size = avpkt->size;

    WMACodecContext *s = avctx->priv_data;

    int nb_frames, bit_offset, i, pos, len, ret;

    uint8_t *q;

    int16_t *samples;



    tprintf(avctx, "***decode_superframe:\n");



    if(buf_size==0){

        s->last_superframe_len = 0;

        return 0;

    }

    if (buf_size < s->block_align)

        return 0;

    buf_size = s->block_align;



    init_get_bits(&s->gb, buf, buf_size*8);



    if (s->use_bit_reservoir) {

        /* read super frame header */

        skip_bits(&s->gb, 4); /* super frame index */

        nb_frames = get_bits(&s->gb, 4) - (s->last_superframe_len <= 0);

    } else {

        nb_frames = 1;

    }



    /* get output buffer */

    s->frame.nb_samples = nb_frames * s->frame_len;

    if ((ret = avctx->get_buffer(avctx, &s->frame)) < 0) {

        av_log(avctx, AV_LOG_ERROR, "get_buffer() failed\n");

        return ret;

    }

    samples = (int16_t *)s->frame.data[0];



    if (s->use_bit_reservoir) {

        bit_offset = get_bits(&s->gb, s->byte_offset_bits + 3);



        if (s->last_superframe_len > 0) {

            //        printf("skip=%d\n", s->last_bitoffset);

            /* add bit_offset bits to last frame */

            if ((s->last_superframe_len + ((bit_offset + 7) >> 3)) >

                MAX_CODED_SUPERFRAME_SIZE)

                goto fail;

            q = s->last_superframe + s->last_superframe_len;

            len = bit_offset;

            while (len > 7) {

                *q++ = (get_bits)(&s->gb, 8);

                len -= 8;

            }

            if (len > 0) {

                *q++ = (get_bits)(&s->gb, len) << (8 - len);

            }



            /* XXX: bit_offset bits into last frame */

            init_get_bits(&s->gb, s->last_superframe, MAX_CODED_SUPERFRAME_SIZE*8);

            /* skip unused bits */

            if (s->last_bitoffset > 0)

                skip_bits(&s->gb, s->last_bitoffset);

            /* this frame is stored in the last superframe and in the

               current one */

            if (wma_decode_frame(s, samples) < 0)

                goto fail;

            samples += s->nb_channels * s->frame_len;

            nb_frames--;

        }



        /* read each frame starting from bit_offset */

        pos = bit_offset + 4 + 4 + s->byte_offset_bits + 3;



        init_get_bits(&s->gb, buf + (pos >> 3), (MAX_CODED_SUPERFRAME_SIZE - (pos >> 3))*8);

        len = pos & 7;

        if (len > 0)

            skip_bits(&s->gb, len);



        s->reset_block_lengths = 1;

        for(i=0;i<nb_frames;i++) {

            if (wma_decode_frame(s, samples) < 0)

                goto fail;

            samples += s->nb_channels * s->frame_len;

        }



        /* we copy the end of the frame in the last frame buffer */

        pos = get_bits_count(&s->gb) + ((bit_offset + 4 + 4 + s->byte_offset_bits + 3) & ~7);

        s->last_bitoffset = pos & 7;

        pos >>= 3;

        len = buf_size - pos;

        if (len > MAX_CODED_SUPERFRAME_SIZE || len < 0) {

            av_log(s->avctx, AV_LOG_ERROR, "len %d invalid\n", len);

            goto fail;

        }

        s->last_superframe_len = len;

        memcpy(s->last_superframe, buf + pos, len);

    } else {

        /* single frame decode */

        if (wma_decode_frame(s, samples) < 0)

            goto fail;

        samples += s->nb_channels * s->frame_len;

    }



//av_log(NULL, AV_LOG_ERROR, "%d %d %d %d outbytes:%d eaten:%d\n", s->frame_len_bits, s->block_len_bits, s->frame_len, s->block_len,        (int8_t *)samples - (int8_t *)data, s->block_align);



    *got_frame_ptr   = 1;

    *(AVFrame *)data = s->frame;



    return s->block_align;

 fail:

    /* when error, we reset the bit reservoir */

    s->last_superframe_len = 0;

    return -1;

}

static int vc1_decode_p_mb(VC1Context *v)

{

    MpegEncContext *s = &v->s;

    GetBitContext *gb = &s->gb;

    int i, j;

    int mb_pos = s->mb_x + s->mb_y * s->mb_stride;

    int cbp; /* cbp decoding stuff */

    int mqdiff, mquant; /* MB quantization */

    int ttmb = v->ttfrm; /* MB Transform type */



    int mb_has_coeffs = 1; /* last_flag */

    int dmv_x, dmv_y; /* Differential MV components */

    int index, index1; /* LUT indexes */

    int val, sign; /* temp values */

    int first_block = 1;

    int dst_idx, off;

    int skipped, fourmv;

    int block_cbp = 0, pat, block_tt = 0, block_intra = 0;



    mquant = v->pq; /* lossy initialization */



    if (v->mv_type_is_raw)

        fourmv = get_bits1(gb);

    else

        fourmv = v->mv_type_mb_plane[mb_pos];

    if (v->skip_is_raw)

        skipped = get_bits1(gb);

    else

        skipped = v->s.mbskip_table[mb_pos];



    if (!fourmv) { /* 1MV mode */

        if (!skipped) {

            GET_MVDATA(dmv_x, dmv_y);



            if (s->mb_intra) {

                s->current_picture.motion_val[1][s->block_index[0]][0] = 0;

                s->current_picture.motion_val[1][s->block_index[0]][1] = 0;

            }

            s->current_picture.mb_type[mb_pos] = s->mb_intra ? MB_TYPE_INTRA : MB_TYPE_16x16;

            vc1_pred_mv(v, 0, dmv_x, dmv_y, 1, v->range_x, v->range_y, v->mb_type[0], 0, 0);



            /* FIXME Set DC val for inter block ? */

            if (s->mb_intra && !mb_has_coeffs) {

                GET_MQUANT();

                s->ac_pred = get_bits1(gb);

                cbp        = 0;

            } else if (mb_has_coeffs) {

                if (s->mb_intra)

                    s->ac_pred = get_bits1(gb);

                cbp = get_vlc2(&v->s.gb, v->cbpcy_vlc->table, VC1_CBPCY_P_VLC_BITS, 2);

                GET_MQUANT();

            } else {

                mquant = v->pq;

                cbp    = 0;

            }

            s->current_picture.qscale_table[mb_pos] = mquant;



            if (!v->ttmbf && !s->mb_intra && mb_has_coeffs)

                ttmb = get_vlc2(gb, ff_vc1_ttmb_vlc[v->tt_index].table,

                                VC1_TTMB_VLC_BITS, 2);

            if (!s->mb_intra) vc1_mc_1mv(v, 0);

            dst_idx = 0;

            for (i = 0; i < 6; i++) {

                s->dc_val[0][s->block_index[i]] = 0;

                dst_idx += i >> 2;

                val = ((cbp >> (5 - i)) & 1);

                off = (i & 4) ? 0 : ((i & 1) * 8 + (i & 2) * 4 * s->linesize);

                v->mb_type[0][s->block_index[i]] = s->mb_intra;

                if (s->mb_intra) {

                    /* check if prediction blocks A and C are available */

                    v->a_avail = v->c_avail = 0;

                    if (i == 2 || i == 3 || !s->first_slice_line)

                        v->a_avail = v->mb_type[0][s->block_index[i] - s->block_wrap[i]];

                    if (i == 1 || i == 3 || s->mb_x)

                        v->c_avail = v->mb_type[0][s->block_index[i] - 1];



                    vc1_decode_intra_block(v, s->block[i], i, val, mquant,

                                           (i & 4) ? v->codingset2 : v->codingset);

                    if ((i>3) && (s->flags & CODEC_FLAG_GRAY))

                        continue;

                    v->vc1dsp.vc1_inv_trans_8x8(s->block[i]);

                    if (v->rangeredfrm)

                        for (j = 0; j < 64; j++)

                            s->block[i][j] <<= 1;

                    s->idsp.put_signed_pixels_clamped(s->block[i],

                                                      s->dest[dst_idx] + off,

                                                      i & 4 ? s->uvlinesize

                                                            : s->linesize);

                    if (v->pq >= 9 && v->overlap) {

                        if (v->c_avail)

                            v->vc1dsp.vc1_h_overlap(s->dest[dst_idx] + off, i & 4 ? s->uvlinesize : s->linesize);

                        if (v->a_avail)

                            v->vc1dsp.vc1_v_overlap(s->dest[dst_idx] + off, i & 4 ? s->uvlinesize : s->linesize);

                    }

                    block_cbp   |= 0xF << (i << 2);

                    block_intra |= 1 << i;

                } else if (val) {

                    pat = vc1_decode_p_block(v, s->block[i], i, mquant, ttmb, first_block,

                                             s->dest[dst_idx] + off, (i & 4) ? s->uvlinesize : s->linesize,

                                             (i & 4) && (s->flags & CODEC_FLAG_GRAY), &block_tt);

                    block_cbp |= pat << (i << 2);

                    if (!v->ttmbf && ttmb < 8)

                        ttmb = -1;

                    first_block = 0;

                }

            }

        } else { // skipped

            s->mb_intra = 0;

            for (i = 0; i < 6; i++) {

                v->mb_type[0][s->block_index[i]] = 0;

                s->dc_val[0][s->block_index[i]]  = 0;

            }

            s->current_picture.mb_type[mb_pos]      = MB_TYPE_SKIP;

            s->current_picture.qscale_table[mb_pos] = 0;

            vc1_pred_mv(v, 0, 0, 0, 1, v->range_x, v->range_y, v->mb_type[0], 0, 0);

            vc1_mc_1mv(v, 0);

        }

    } else { // 4MV mode

        if (!skipped /* unskipped MB */) {

            int intra_count = 0, coded_inter = 0;

            int is_intra[6], is_coded[6];

            /* Get CBPCY */

            cbp = get_vlc2(&v->s.gb, v->cbpcy_vlc->table, VC1_CBPCY_P_VLC_BITS, 2);

            for (i = 0; i < 6; i++) {

                val = ((cbp >> (5 - i)) & 1);

                s->dc_val[0][s->block_index[i]] = 0;

                s->mb_intra                     = 0;

                if (i < 4) {

                    dmv_x = dmv_y = 0;

                    s->mb_intra   = 0;

                    mb_has_coeffs = 0;

                    if (val) {

                        GET_MVDATA(dmv_x, dmv_y);

                    }

                    vc1_pred_mv(v, i, dmv_x, dmv_y, 0, v->range_x, v->range_y, v->mb_type[0], 0, 0);

                    if (!s->mb_intra)

                        vc1_mc_4mv_luma(v, i, 0, 0);

                    intra_count += s->mb_intra;

                    is_intra[i]  = s->mb_intra;

                    is_coded[i]  = mb_has_coeffs;

                }

                if (i & 4) {

                    is_intra[i] = (intra_count >= 3);

                    is_coded[i] = val;

                }

                if (i == 4)

                    vc1_mc_4mv_chroma(v, 0);

                v->mb_type[0][s->block_index[i]] = is_intra[i];

                if (!coded_inter)

                    coded_inter = !is_intra[i] && is_coded[i];

            }

            // if there are no coded blocks then don't do anything more

            dst_idx = 0;

            if (!intra_count && !coded_inter)

                goto end;

            GET_MQUANT();

            s->current_picture.qscale_table[mb_pos] = mquant;

            /* test if block is intra and has pred */

            {

                int intrapred = 0;

                for (i = 0; i < 6; i++)

                    if (is_intra[i]) {

                        if (((!s->first_slice_line || (i == 2 || i == 3)) && v->mb_type[0][s->block_index[i] - s->block_wrap[i]])

                            || ((s->mb_x || (i == 1 || i == 3)) && v->mb_type[0][s->block_index[i] - 1])) {

                            intrapred = 1;

                            break;

                        }

                    }

                if (intrapred)

                    s->ac_pred = get_bits1(gb);

                else

                    s->ac_pred = 0;

            }

            if (!v->ttmbf && coded_inter)

                ttmb = get_vlc2(gb, ff_vc1_ttmb_vlc[v->tt_index].table, VC1_TTMB_VLC_BITS, 2);

            for (i = 0; i < 6; i++) {

                dst_idx    += i >> 2;

                off         = (i & 4) ? 0 : ((i & 1) * 8 + (i & 2) * 4 * s->linesize);

                s->mb_intra = is_intra[i];

                if (is_intra[i]) {

                    /* check if prediction blocks A and C are available */

                    v->a_avail = v->c_avail = 0;

                    if (i == 2 || i == 3 || !s->first_slice_line)

                        v->a_avail = v->mb_type[0][s->block_index[i] - s->block_wrap[i]];

                    if (i == 1 || i == 3 || s->mb_x)

                        v->c_avail = v->mb_type[0][s->block_index[i] - 1];



                    vc1_decode_intra_block(v, s->block[i], i, is_coded[i], mquant,

                                           (i & 4) ? v->codingset2 : v->codingset);

                    if ((i>3) && (s->flags & CODEC_FLAG_GRAY))

                        continue;

                    v->vc1dsp.vc1_inv_trans_8x8(s->block[i]);

                    if (v->rangeredfrm)

                        for (j = 0; j < 64; j++)

                            s->block[i][j] <<= 1;

                    s->idsp.put_signed_pixels_clamped(s->block[i],

                                                      s->dest[dst_idx] + off,

                                                      (i & 4) ? s->uvlinesize

                                                              : s->linesize);

                    if (v->pq >= 9 && v->overlap) {

                        if (v->c_avail)

                            v->vc1dsp.vc1_h_overlap(s->dest[dst_idx] + off, i & 4 ? s->uvlinesize : s->linesize);

                        if (v->a_avail)

                            v->vc1dsp.vc1_v_overlap(s->dest[dst_idx] + off, i & 4 ? s->uvlinesize : s->linesize);

                    }

                    block_cbp   |= 0xF << (i << 2);

                    block_intra |= 1 << i;

                } else if (is_coded[i]) {

                    pat = vc1_decode_p_block(v, s->block[i], i, mquant, ttmb,

                                             first_block, s->dest[dst_idx] + off,

                                             (i & 4) ? s->uvlinesize : s->linesize,

                                             (i & 4) && (s->flags & CODEC_FLAG_GRAY),

                                             &block_tt);

                    block_cbp |= pat << (i << 2);

                    if (!v->ttmbf && ttmb < 8)

                        ttmb = -1;

                    first_block = 0;

                }

            }

        } else { // skipped MB

            s->mb_intra                               = 0;

            s->current_picture.qscale_table[mb_pos] = 0;

            for (i = 0; i < 6; i++) {

                v->mb_type[0][s->block_index[i]] = 0;

                s->dc_val[0][s->block_index[i]]  = 0;

            }

            for (i = 0; i < 4; i++) {

                vc1_pred_mv(v, i, 0, 0, 0, v->range_x, v->range_y, v->mb_type[0], 0, 0);

                vc1_mc_4mv_luma(v, i, 0, 0);

            }

            vc1_mc_4mv_chroma(v, 0);

            s->current_picture.qscale_table[mb_pos] = 0;

        }

    }

end:

    v->cbp[s->mb_x]      = block_cbp;

    v->ttblk[s->mb_x]    = block_tt;

    v->is_intra[s->mb_x] = block_intra;



    return 0;

}

