                s->dc_val[0][s->block_index[i]]  = 0;

            }

            s->current_picture.mb_type[mb_pos]      = MB_TYPE_SKIP;

            s->current_picture.qscale_table[mb_pos] = 0;

            vc1_pred_mv(v, 0, 0, 0, 1, v->range_x, v->range_y, v->mb_type[0], 0, 0);

            vc1_mc_1mv(v, 0);

        }

    } else { // 4MV mode

        if (!skipped /* unskipped MB */) {

            int intra_count = 0, coded_inter = 0;

            int is_intra[6], is_coded[6];

            /* Get CBPCY */

            cbp = get_vlc2(&v->s.gb, v->cbpcy_vlc->table, VC1_CBPCY_P_VLC_BITS, 2);

            for (i = 0; i < 6; i++) {

                val = ((cbp >> (5 - i)) & 1);

                s->dc_val[0][s->block_index[i]] = 0;

                s->mb_intra                     = 0;

                if (i < 4) {

                    dmv_x = dmv_y = 0;

                    s->mb_intra   = 0;

                    mb_has_coeffs = 0;

                    if (val) {

                        GET_MVDATA(dmv_x, dmv_y);

                    }

                    vc1_pred_mv(v, i, dmv_x, dmv_y, 0, v->range_x, v->range_y, v->mb_type[0], 0, 0);

                    if (!s->mb_intra)

                        vc1_mc_4mv_luma(v, i, 0, 0);

                    intra_count += s->mb_intra;

                    is_intra[i]  = s->mb_intra;

                    is_coded[i]  = mb_has_coeffs;

                }

                if (i & 4) {

                    is_intra[i] = (intra_count >= 3);

                    is_coded[i] = val;

                }

                if (i == 4)

                    vc1_mc_4mv_chroma(v, 0);

                v->mb_type[0][s->block_index[i]] = is_intra[i];

                if (!coded_inter)

                    coded_inter = !is_intra[i] && is_coded[i];

            }

            // if there are no coded blocks then don't do anything more

            dst_idx = 0;

            if (!intra_count && !coded_inter)

                goto end;

            GET_MQUANT();

            s->current_picture.qscale_table[mb_pos] = mquant;

            /* test if block is intra and has pred */

            {

                int intrapred = 0;

                for (i = 0; i < 6; i++)

                    if (is_intra[i]) {

                        if (((!s->first_slice_line || (i == 2 || i == 3)) && v->mb_type[0][s->block_index[i] - s->block_wrap[i]])

                            || ((s->mb_x || (i == 1 || i == 3)) && v->mb_type[0][s->block_index[i] - 1])) {

                            intrapred = 1;

                            break;

                        }

                    }

                if (intrapred)

                    s->ac_pred = get_bits1(gb);

                else

                    s->ac_pred = 0;

            }

            if (!v->ttmbf && coded_inter)

                ttmb = get_vlc2(gb, ff_vc1_ttmb_vlc[v->tt_index].table, VC1_TTMB_VLC_BITS, 2);

            for (i = 0; i < 6; i++) {

                dst_idx    += i >> 2;

                off         = (i & 4) ? 0 : ((i & 1) * 8 + (i & 2) * 4 * s->linesize);

                s->mb_intra = is_intra[i];

                if (is_intra[i]) {

                    /* check if prediction blocks A and C are available */

                    v->a_avail = v->c_avail = 0;

                    if (i == 2 || i == 3 || !s->first_slice_line)

                        v->a_avail = v->mb_type[0][s->block_index[i] - s->block_wrap[i]];

                    if (i == 1 || i == 3 || s->mb_x)

                        v->c_avail = v->mb_type[0][s->block_index[i] - 1];



                    vc1_decode_intra_block(v, s->block[i], i, is_coded[i], mquant,

                                           (i & 4) ? v->codingset2 : v->codingset);

                    if ((i>3) && (s->flags & CODEC_FLAG_GRAY))

                        continue;

                    v->vc1dsp.vc1_inv_trans_8x8(s->block[i]);

                    if (v->rangeredfrm)

                        for (j = 0; j < 64; j++)

                            s->block[i][j] <<= 1;

                    s->idsp.put_signed_pixels_clamped(s->block[i],

                                                      s->dest[dst_idx] + off,

                                                      (i & 4) ? s->uvlinesize

                                                              : s->linesize);

                    if (v->pq >= 9 && v->overlap) {

                        if (v->c_avail)

                            v->vc1dsp.vc1_h_overlap(s->dest[dst_idx] + off, i & 4 ? s->uvlinesize : s->linesize);

                        if (v->a_avail)

                            v->vc1dsp.vc1_v_overlap(s->dest[dst_idx] + off, i & 4 ? s->uvlinesize : s->linesize);

                    }

                    block_cbp   |= 0xF << (i << 2);

                    block_intra |= 1 << i;

                } else if (is_coded[i]) {

                    pat = vc1_decode_p_block(v, s->block[i], i, mquant, ttmb,

                                             first_block, s->dest[dst_idx] + off,

                                             (i & 4) ? s->uvlinesize : s->linesize,

                                             (i & 4) && (s->flags & CODEC_FLAG_GRAY),

                                             &block_tt);

                    block_cbp |= pat << (i << 2);

                    if (!v->ttmbf && ttmb < 8)

                        ttmb = -1;

                    first_block = 0;

                }

            }

        } else { // skipped MB

            s->mb_intra                               = 0;

            s->current_picture.qscale_table[mb_pos] = 0;

            for (i = 0; i < 6; i++) {

                v->mb_type[0][s->block_index[i]] = 0;

                s->dc_val[0][s->block_index[i]]  = 0;

            }

            for (i = 0; i < 4; i++) {

                vc1_pred_mv(v, i, 0, 0, 0, v->range_x, v->range_y, v->mb_type[0], 0, 0);

                vc1_mc_4mv_luma(v, i, 0, 0);

            }

            vc1_mc_4mv_chroma(v, 0);

            s->current_picture.qscale_table[mb_pos] = 0;

        }

    }

end:

    v->cbp[s->mb_x]      = block_cbp;

    v->ttblk[s->mb_x]    = block_tt;

    v->is_intra[s->mb_x] = block_intra;



    return 0;

}

