static inline int decode_subframe(FLACContext *s, int channel)

{

    int32_t *decoded = s->decoded[channel];

    int type, wasted = 0;

    int bps = s->flac_stream_info.bps;

    int i, tmp, ret;



    if (channel == 0) {

        if (s->ch_mode == FLAC_CHMODE_RIGHT_SIDE)

            bps++;

    } else {

        if (s->ch_mode == FLAC_CHMODE_LEFT_SIDE || s->ch_mode == FLAC_CHMODE_MID_SIDE)

            bps++;

    }



    if (get_bits1(&s->gb)) {

        av_log(s->avctx, AV_LOG_ERROR, "invalid subframe padding\n");

        return AVERROR_INVALIDDATA;

    }

    type = get_bits(&s->gb, 6);



    if (get_bits1(&s->gb)) {

        int left = get_bits_left(&s->gb);

        if ( left <= 0 ||

            (left < bps && !show_bits_long(&s->gb, left)) ||

                           !show_bits_long(&s->gb, bps)) {

            av_log(s->avctx, AV_LOG_ERROR,

                   "Invalid number of wasted bits > available bits (%d) - left=%d\n",

                   bps, left);

            return AVERROR_INVALIDDATA;

        }

        wasted = 1 + get_unary(&s->gb, 1, get_bits_left(&s->gb));

        bps -= wasted;

    }

    if (bps > 32) {

        avpriv_report_missing_feature(s->avctx, "Decorrelated bit depth > 32");

        return AVERROR_PATCHWELCOME;

    }



//FIXME use av_log2 for types

    if (type == 0) {

        tmp = get_sbits_long(&s->gb, bps);

        for (i = 0; i < s->blocksize; i++)

            decoded[i] = tmp;

    } else if (type == 1) {

        for (i = 0; i < s->blocksize; i++)

            decoded[i] = get_sbits_long(&s->gb, bps);

    } else if ((type >= 8) && (type <= 12)) {

        if ((ret = decode_subframe_fixed(s, decoded, type & ~0x8, bps)) < 0)

            return ret;

    } else if (type >= 32) {

        if ((ret = decode_subframe_lpc(s, decoded, (type & ~0x20)+1, bps)) < 0)

            return ret;

    } else {

        av_log(s->avctx, AV_LOG_ERROR, "invalid coding type\n");

        return AVERROR_INVALIDDATA;

    }



    if (wasted) {

        int i;

        for (i = 0; i < s->blocksize; i++)

            decoded[i] <<= wasted;

    }



    return 0;

}

static void icp_set_cppr(struct icp_state *icp, int server, uint8_t cppr)

{

    struct icp_server_state *ss = icp->ss + server;

    uint8_t old_cppr;

    uint32_t old_xisr;



    old_cppr = CPPR(ss);

    ss->xirr = (ss->xirr & ~CPPR_MASK) | (cppr << 24);



    if (cppr < old_cppr) {

        if (XISR(ss) && (cppr <= ss->pending_priority)) {

            old_xisr = XISR(ss);

