static unsigned int get_video_format_idx(AVCodecContext *avctx)

{

    unsigned int ret_idx = 0;

    unsigned int idx;

    unsigned int num_formats = sizeof(ff_schro_video_format_info) /

                               sizeof(ff_schro_video_format_info[0]);



