        if (use_gdb_syscalls()) {

            gdb_do_syscall(m68k_semi_cb, "unlink,%s",

                           ARG(0), (int)ARG(1));

            return;

        } else {

            if (!(p = lock_user_string(ARG(0)))) {

                /* FIXME - check error code? */

                result = -1;

            } else {

                result = unlink(p);

                unlock_user(p, ARG(0), 0);

            }

        }

        break;

    case HOSTED_STAT:

        if (use_gdb_syscalls()) {

            gdb_do_syscall(m68k_semi_cb, "stat,%s,%x",

                           ARG(0), (int)ARG(1), ARG(2));

            return;

        } else {

            struct stat s;

            if (!(p = lock_user_string(ARG(0)))) {

                /* FIXME - check error code? */

                result = -1;

            } else {

                result = stat(p, &s);

                unlock_user(p, ARG(0), 0);

            }

            if (result == 0) {

                translate_stat(env, ARG(2), &s);

            }

        }

        break;

    case HOSTED_FSTAT:

        if (use_gdb_syscalls()) {

            gdb_do_syscall(m68k_semi_cb, "fstat,%x,%x",

                           ARG(0), ARG(1));

            return;

        } else {

            struct stat s;

            result = fstat(ARG(0), &s);

            if (result == 0) {

                translate_stat(env, ARG(1), &s);

            }

        }

        break;

    case HOSTED_GETTIMEOFDAY:

        if (use_gdb_syscalls()) {

            gdb_do_syscall(m68k_semi_cb, "gettimeofday,%x,%x",

                           ARG(0), ARG(1));

            return;

        } else {

            qemu_timeval tv;

            struct gdb_timeval *p;

            result = qemu_gettimeofday(&tv);

            if (result != 0) {

                if (!(p = lock_user(VERIFY_WRITE,

                                    ARG(0), sizeof(struct gdb_timeval), 0))) {

                    /* FIXME - check error code? */

                    result = -1;

                } else {

                    p->tv_sec = cpu_to_be32(tv.tv_sec);

                    p->tv_usec = cpu_to_be64(tv.tv_usec);

                    unlock_user(p, ARG(0), sizeof(struct gdb_timeval));

                }

            }

        }

        break;

    case HOSTED_ISATTY:

        if (use_gdb_syscalls()) {

            gdb_do_syscall(m68k_semi_cb, "isatty,%x", ARG(0));

            return;

        } else {

            result = isatty(ARG(0));

        }

        break;

    case HOSTED_SYSTEM:

        if (use_gdb_syscalls()) {

            gdb_do_syscall(m68k_semi_cb, "system,%s",

                           ARG(0), (int)ARG(1));

            return;

        } else {

            if (!(p = lock_user_string(ARG(0)))) {

                /* FIXME - check error code? */

                result = -1;

            } else {

                result = system(p);

                unlock_user(p, ARG(0), 0);

            }

        }

        break;

    case HOSTED_INIT_SIM:

#if defined(CONFIG_USER_ONLY)

        {

        TaskState *ts = env->opaque;

        /* Allocate the heap using sbrk.  */

        if (!ts->heap_limit) {

            long ret;

            uint32_t size;

            uint32_t base;



            base = do_brk(0);

            size = SEMIHOSTING_HEAP_SIZE;

            /* Try a big heap, and reduce the size if that fails.  */

            for (;;) {

