                                                       src_h[1][0], alpha, width);

                } else if (ysub[1]) {

                    v->vc1dsp.sprite_v_double_onescale(dst, src_h[1][0], src_h[1][1], ysub[1],

                                                       src_h[0][0], (1<<16)-1-alpha, width);

