int load_vmstate(const char *name)

{

    BlockDriverState *bs, *bs1;

    QEMUSnapshotInfo sn;

    QEMUFile *f;

    int ret;



    /* Verify if there is a device that doesn't support snapshots and is writable */

    bs = NULL;

    while ((bs = bdrv_next(bs))) {



        if (bdrv_is_removable(bs) || bdrv_is_read_only(bs)) {

            continue;

        }



        if (!bdrv_can_snapshot(bs)) {

            error_report("Device '%s' is writable but does not support snapshots.",

                               bdrv_get_device_name(bs));

            return -ENOTSUP;

        }

    }



    bs = bdrv_snapshots();

    if (!bs) {

        error_report("No block device supports snapshots");

        return -EINVAL;

    }



    /* Flush all IO requests so they don't interfere with the new state.  */

    qemu_aio_flush();



    bs1 = NULL;

    while ((bs1 = bdrv_next(bs1))) {

        if (bdrv_can_snapshot(bs1)) {

            ret = bdrv_snapshot_goto(bs1, name);

            if (ret < 0) {

                switch(ret) {

                case -ENOTSUP:

                    error_report("%sSnapshots not supported on device '%s'",

                                 bs != bs1 ? "Warning: " : "",

                                 bdrv_get_device_name(bs1));

                    break;

                case -ENOENT:

                    error_report("%sCould not find snapshot '%s' on device '%s'",

                                 bs != bs1 ? "Warning: " : "",

                                 name, bdrv_get_device_name(bs1));

                    break;

                default:

                    error_report("%sError %d while activating snapshot on '%s'",

                                 bs != bs1 ? "Warning: " : "",

                                 ret, bdrv_get_device_name(bs1));

                    break;

                }

                /* fatal on snapshot block device */

                if (bs == bs1)

                    return 0;

            }

        }

    }



    /* Don't even try to load empty VM states */

    ret = bdrv_snapshot_find(bs, &sn, name);

    if ((ret >= 0) && (sn.vm_state_size == 0))

        return -EINVAL;



    /* restore the VM state */

    f = qemu_fopen_bdrv(bs, 0);

    if (!f) {

        error_report("Could not open VM state file");

        return -EINVAL;

    }

    ret = qemu_loadvm_state(f);

    qemu_fclose(f);

    if (ret < 0) {

        error_report("Error %d while loading VM state", ret);

        return ret;

    }

    return 0;

}

static int flv_write_header(AVFormatContext *s)

{

    AVIOContext *pb = s->pb;

    FLVContext *flv = s->priv_data;

    AVCodecContext *audio_enc = NULL, *video_enc = NULL, *data_enc = NULL;

    int i, metadata_count = 0;

    double framerate = 0.0;

    int64_t metadata_size_pos, data_size, metadata_count_pos;

    AVDictionaryEntry *tag = NULL;



    for (i = 0; i < s->nb_streams; i++) {

        AVCodecContext *enc = s->streams[i]->codec;

        FLVStreamContext *sc;

        switch (enc->codec_type) {

        case AVMEDIA_TYPE_VIDEO:

            if (s->streams[i]->r_frame_rate.den &&

                s->streams[i]->r_frame_rate.num) {

                framerate = av_q2d(s->streams[i]->r_frame_rate);

            } else {

                framerate = 1 / av_q2d(s->streams[i]->codec->time_base);

            }

            video_enc = enc;

            if (enc->codec_tag == 0) {

                av_log(s, AV_LOG_ERROR, "video codec not compatible with flv\n");

                return -1;

            }

            break;

        case AVMEDIA_TYPE_AUDIO:

            audio_enc = enc;

            if (get_audio_flags(s, enc) < 0)

                return AVERROR_INVALIDDATA;

            break;

        case AVMEDIA_TYPE_DATA:

            if (enc->codec_id != CODEC_ID_TEXT) {

                av_log(s, AV_LOG_ERROR, "codec not compatible with flv\n");

                return AVERROR_INVALIDDATA;

            }

            data_enc = enc;

            break;

        default:

            av_log(s, AV_LOG_ERROR, "codec not compatible with flv\n");

            return -1;

        }

        avpriv_set_pts_info(s->streams[i], 32, 1, 1000); /* 32 bit pts in ms */



        sc = av_mallocz(sizeof(FLVStreamContext));

        if (!sc)

            return AVERROR(ENOMEM);

        s->streams[i]->priv_data = sc;

        sc->last_ts = -1;

    }



    flv->delay = AV_NOPTS_VALUE;



    avio_write(pb, "FLV", 3);

    avio_w8(pb, 1);

    avio_w8(pb, FLV_HEADER_FLAG_HASAUDIO * !!audio_enc +

                FLV_HEADER_FLAG_HASVIDEO * !!video_enc);

    avio_wb32(pb, 9);

    avio_wb32(pb, 0);



    for (i = 0; i < s->nb_streams; i++)

        if (s->streams[i]->codec->codec_tag == 5) {

            avio_w8(pb, 8);     // message type

            avio_wb24(pb, 0);   // include flags

            avio_wb24(pb, 0);   // time stamp

            avio_wb32(pb, 0);   // reserved

            avio_wb32(pb, 11);  // size

            flv->reserved = 5;

        }



    /* write meta_tag */

    avio_w8(pb, 18);            // tag type META

    metadata_size_pos = avio_tell(pb);

    avio_wb24(pb, 0);           // size of data part (sum of all parts below)

    avio_wb24(pb, 0);           // timestamp

    avio_wb32(pb, 0);           // reserved



    /* now data of data_size size */



    /* first event name as a string */

    avio_w8(pb, AMF_DATA_TYPE_STRING);

    put_amf_string(pb, "onMetaData"); // 12 bytes



    /* mixed array (hash) with size and string/type/data tuples */

    avio_w8(pb, AMF_DATA_TYPE_MIXEDARRAY);

    metadata_count_pos = avio_tell(pb);

    metadata_count = 5 * !!video_enc +

                     5 * !!audio_enc +

                     1 * !!data_enc  +

                     2; // +2 for duration and file size



    avio_wb32(pb, metadata_count);



    put_amf_string(pb, "duration");

    flv->duration_offset= avio_tell(pb);



    // fill in the guessed duration, it'll be corrected later if incorrect

    put_amf_double(pb, s->duration / AV_TIME_BASE);



    if (video_enc) {

        put_amf_string(pb, "width");

        put_amf_double(pb, video_enc->width);



        put_amf_string(pb, "height");

        put_amf_double(pb, video_enc->height);



        put_amf_string(pb, "videodatarate");

        put_amf_double(pb, video_enc->bit_rate / 1024.0);



        put_amf_string(pb, "framerate");

        put_amf_double(pb, framerate);



        put_amf_string(pb, "videocodecid");

        put_amf_double(pb, video_enc->codec_tag);

    }



    if (audio_enc) {

        put_amf_string(pb, "audiodatarate");

        put_amf_double(pb, audio_enc->bit_rate / 1024.0);



        put_amf_string(pb, "audiosamplerate");

        put_amf_double(pb, audio_enc->sample_rate);



        put_amf_string(pb, "audiosamplesize");

        put_amf_double(pb, audio_enc->codec_id == CODEC_ID_PCM_U8 ? 8 : 16);



        put_amf_string(pb, "stereo");

        put_amf_bool(pb, audio_enc->channels == 2);



        put_amf_string(pb, "audiocodecid");

        put_amf_double(pb, audio_enc->codec_tag);

    }



    if (data_enc) {

        put_amf_string(pb, "datastream");

        put_amf_double(pb, 0.0);

    }



    while ((tag = av_dict_get(s->metadata, "", tag, AV_DICT_IGNORE_SUFFIX))) {

        put_amf_string(pb, tag->key);

        avio_w8(pb, AMF_DATA_TYPE_STRING);

        put_amf_string(pb, tag->value);

        metadata_count++;

    }



    put_amf_string(pb, "filesize");

    flv->filesize_offset = avio_tell(pb);

    put_amf_double(pb, 0); // delayed write



    put_amf_string(pb, "");

    avio_w8(pb, AMF_END_OF_OBJECT);



    /* write total size of tag */

    data_size = avio_tell(pb) - metadata_size_pos - 10;



    avio_seek(pb, metadata_count_pos, SEEK_SET);

    avio_wb32(pb, metadata_count);



    avio_seek(pb, metadata_size_pos, SEEK_SET);

    avio_wb24(pb, data_size);

    avio_skip(pb, data_size + 10 - 3);

    avio_wb32(pb, data_size + 11);



    for (i = 0; i < s->nb_streams; i++) {

        AVCodecContext *enc = s->streams[i]->codec;

        if (enc->codec_id == CODEC_ID_AAC || enc->codec_id == CODEC_ID_H264) {

            int64_t pos;

            avio_w8(pb, enc->codec_type == AVMEDIA_TYPE_VIDEO ?

                    FLV_TAG_TYPE_VIDEO : FLV_TAG_TYPE_AUDIO);

            avio_wb24(pb, 0); // size patched later

            avio_wb24(pb, 0); // ts

            avio_w8(pb, 0);   // ts ext

            avio_wb24(pb, 0); // streamid

            pos = avio_tell(pb);

            if (enc->codec_id == CODEC_ID_AAC) {

                avio_w8(pb, get_audio_flags(s, enc));

                avio_w8(pb, 0); // AAC sequence header

                avio_write(pb, enc->extradata, enc->extradata_size);

            } else {

                avio_w8(pb, enc->codec_tag | FLV_FRAME_KEY); // flags

                avio_w8(pb, 0); // AVC sequence header

                avio_wb24(pb, 0); // composition time

                ff_isom_write_avcc(pb, enc->extradata, enc->extradata_size);

            }

            data_size = avio_tell(pb) - pos;

            avio_seek(pb, -data_size - 10, SEEK_CUR);

            avio_wb24(pb, data_size);

            avio_skip(pb, data_size + 10 - 3);

            avio_wb32(pb, data_size + 11); // previous tag size

        }

    }



    return 0;

}

void ff_htmlmarkup_to_ass(void *log_ctx, AVBPrint *dst, const char *in)

{

    char *param, buffer[128], tmp[128];

    int len, tag_close, sptr = 1, line_start = 1, an = 0, end = 0;

    SrtStack stack[16];



    stack[0].tag[0] = 0;

    strcpy(stack[0].param[PARAM_SIZE],  "{\\fs}");

    strcpy(stack[0].param[PARAM_COLOR], "{\\c}");

    strcpy(stack[0].param[PARAM_FACE],  "{\\fn}");



    for (; !end && *in; in++) {

        switch (*in) {

        case '\r':

            break;

        case '\n':

            if (line_start) {

                end = 1;

                break;

            }

            rstrip_spaces_buf(dst);

            av_bprintf(dst, "\\N");

            line_start = 1;

            break;

        case ' ':

            if (!line_start)

                av_bprint_chars(dst, *in, 1);

            break;

        case '{':    /* skip all {\xxx} substrings except for {\an%d}

                        and all microdvd like styles such as {Y:xxx} */

            len = 0;

            an += sscanf(in, "{\\an%*1u}%n", &len) >= 0 && len > 0;

            if ((an != 1 && (len = 0, sscanf(in, "{\\%*[^}]}%n", &len) >= 0 && len > 0)) ||

                (len = 0, sscanf(in, "{%*1[CcFfoPSsYy]:%*[^}]}%n", &len) >= 0 && len > 0)) {

                in += len - 1;

            } else

                av_bprint_chars(dst, *in, 1);

            break;

        case '<':

            tag_close = in[1] == '/';

            len = 0;

            if (sscanf(in+tag_close+1, "%127[^>]>%n", buffer, &len) >= 1 && len > 0) {

                const char *tagname = buffer;

                while (*tagname == ' ')

                    tagname++;

                if ((param = strchr(tagname, ' ')))

                    *param++ = 0;

                if ((!tag_close && sptr < FF_ARRAY_ELEMS(stack)) ||

                    ( tag_close && sptr > 0 && !strcmp(stack[sptr-1].tag, tagname))) {

                    int i, j, unknown = 0;

                    in += len + tag_close;

                    if (!tag_close)

                        memset(stack+sptr, 0, sizeof(*stack));

                    if (!strcmp(tagname, "font")) {

                        if (tag_close) {

                            for (i=PARAM_NUMBER-1; i>=0; i--)

                                if (stack[sptr-1].param[i][0])

                                    for (j=sptr-2; j>=0; j--)

                                        if (stack[j].param[i][0]) {

                                            av_bprintf(dst, "%s", stack[j].param[i]);

                                            break;

                                        }

                        } else {

                            while (param) {

                                if (!strncmp(param, "size=", 5)) {

                                    unsigned font_size;

                                    param += 5 + (param[5] == '"');

                                    if (sscanf(param, "%u", &font_size) == 1) {

                                        snprintf(stack[sptr].param[PARAM_SIZE],

                                             sizeof(stack[0].param[PARAM_SIZE]),

                                             "{\\fs%u}", font_size);

                                    }

                                } else if (!strncmp(param, "color=", 6)) {

                                    param += 6 + (param[6] == '"');

                                    snprintf(stack[sptr].param[PARAM_COLOR],

                                         sizeof(stack[0].param[PARAM_COLOR]),

                                         "{\\c&H%X&}",

                                         html_color_parse(log_ctx, param));

                                } else if (!strncmp(param, "face=", 5)) {

                                    param += 5 + (param[5] == '"');

                                    len = strcspn(param,

                                                  param[-1] == '"' ? "\"" :" ");

                                    av_strlcpy(tmp, param,

                                               FFMIN(sizeof(tmp), len+1));

                                    param += len;

                                    snprintf(stack[sptr].param[PARAM_FACE],

                                             sizeof(stack[0].param[PARAM_FACE]),

                                             "{\\fn%s}", tmp);

                                }

                                if ((param = strchr(param, ' ')))

                                    param++;

                            }

                            for (i=0; i<PARAM_NUMBER; i++)

                                if (stack[sptr].param[i][0])

                                    av_bprintf(dst, "%s", stack[sptr].param[i]);

                        }

                    } else if (tagname[0] && !tagname[1] && strspn(tagname, "bisu") == 1) {

                        av_bprintf(dst, "{\\%c%d}", tagname[0], !tag_close);

                    } else {

                        unknown = 1;

                        snprintf(tmp, sizeof(tmp), "</%s>", tagname);

                    }

                    if (tag_close) {

                        sptr--;

                    } else if (unknown && !strstr(in, tmp)) {

                        in -= len + tag_close;

                        av_bprint_chars(dst, *in, 1);

                    } else

                        av_strlcpy(stack[sptr++].tag, tagname,

                                   sizeof(stack[0].tag));

                    break;

                }

            }

        default:

            av_bprint_chars(dst, *in, 1);

            break;

        }

        if (*in != ' ' && *in != '\r' && *in != '\n')

            line_start = 0;

    }



    while (dst->len >= 2 && !strncmp(&dst->str[dst->len - 2], "\\N", 2))

        dst->len -= 2;

    dst->str[dst->len] = 0;

    rstrip_spaces_buf(dst);

}

